import React from 'react';
import {
  Home,
  LayoutDashboard,
  Bell,
  Database,
  FileBarChart,
  Users,
  Activity,
  Settings,
} from 'lucide-react';

const NAV_ITEMS = [
  { id: 'home', label: 'Home', icon: Home },
  { id: 'dashboards', label: 'Dashboards', icon: LayoutDashboard },
  { id: 'alerts', label: 'Alerts', icon: Bell },
  { id: 'data-sources', label: 'Data Sources', icon: Database },
  { id: 'reports', label: 'Reports', icon: FileBarChart },
  { id: 'user-management', label: 'User Management', icon: Users },
  { id: 'system-status', label: 'System Status', icon: Activity },
  { id: 'settings', label: 'Settings', icon: Settings },
];

export default function Sidebar({
  activeNavId = 'home',
  onNavChange,
}) {
  return (
    <aside className="layout-sidebar" aria-label="Main navigation">
      <div className="layout-sidebar__brand">
        <div className="layout-sidebar__brand-mark" aria-hidden>
          O
        </div>
        <span className="layout-sidebar__brand-text">OpSight</span>
      </div>
      <nav className="layout-sidebar__nav">
        {NAV_ITEMS.map(({ id, label, icon: Icon }) => {
          const isActive = id === activeNavId;
          return (
            <button
              key={id}
              type="button"
              className={
                'layout-sidebar__link' +
                (isActive ? ' layout-sidebar__link--active' : '')
              }
              aria-current={isActive ? 'page' : undefined}
              onClick={() => onNavChange && onNavChange(id)}
            >
              <Icon size={20} strokeWidth={2} aria-hidden />
              <span>{label}</span>
            </button>
          );
        })}
      </nav>
    </aside>
  );
}
